import './style.css';
import PremblyPass from 'prembly-pass';

const verifyBtn = document.getElementById('verify-btn');
const resultDiv = document.getElementById('result');

// Retrieve the API key from Vite's environment variable or the injected process.env
const apiKey = import.meta.env.VITE_PREMBLY_API_KEY || process.env.PREMBLY_API_KEY;

// Initialize PremblyPass as per requirements
const premblyWidget = new PremblyPass({
  app_id: 'test_app_id',
  x_api_key: apiKey,
  environment: 'test',
  url: 'https://api.prembly.com',
  config_id: 'test_config_id',
  user_ref: 'user_' + Date.now() + '_' + Math.random().toString(36).substring(7)
});

// Assuming event listeners can be attached like this based on typical JS widget patterns
if (typeof premblyWidget.on === 'function') {
  premblyWidget.on('success', (result) => {
    console.log('Verification Success:', result);
    resultDiv.innerHTML = `<p style="color: green;">Success: ${JSON.stringify(result)}</p>`;
  });

  premblyWidget.on('error', (error) => {
    console.error('Verification Error:', error);
    resultDiv.innerHTML = `<p style="color: red;">Error: ${JSON.stringify(error)}</p>`;
  });
} else {
  // If the widget uses callbacks in config instead
  premblyWidget.onSuccess = (result) => {
    console.log('Verification Success:', result);
    resultDiv.innerHTML = `<p style="color: green;">Success: ${JSON.stringify(result)}</p>`;
  };
  premblyWidget.onError = (error) => {
    console.error('Verification Error:', error);
    resultDiv.innerHTML = `<p style="color: red;">Error: ${JSON.stringify(error)}</p>`;
  };
}

verifyBtn.addEventListener('click', () => {
  if (typeof premblyWidget.launch === 'function') {
    premblyWidget.launch();
  } else if (typeof premblyWidget.open === 'function') {
    premblyWidget.open();
  } else if (typeof premblyWidget.start === 'function') {
    premblyWidget.start();
  } else {
    console.warn('Could not determine how to launch the widget. Ensure the correct method is used.');
  }
});

