  <div>
    <h1>Prembly Verification</h1>
    <button id="verify-btn">Verify Identity</button>
    <div id="result" style="margin-top: 20px;"></div>
  </div>
`;

const verifyBtn = document.getElementById('verify-btn');
const resultDiv = document.getElementById('result');

// Retrieve the API key from Vite's environment variable or the injected process.env
const apiKey = import.meta.env.VITE_PREMBLY_API_KEY || process.env.PREMBLY_API_KEY || '';

let premblyWidget;

try {
  // Initialize PremblyPass as per requirements
  const config = {
    app_id: 'test_app_id',
    x_api_key: apiKey,
    environment: 'test',
    url: 'https://api.prembly.com',
    config_id: 'test_config_id',
    user_ref: 'user_' + Date.now() + '_' + Math.random().toString(36).substring(7)
  };

  // If PremblyPass is an object with an init method (another common pattern)
  if (typeof PremblyPass === 'function') {
    premblyWidget = new PremblyPass(config);
  } else if (PremblyPass && typeof PremblyPass.init === 'function') {
    premblyWidget = PremblyPass.init(config);
  } else if (window.PremblyPass && typeof window.PremblyPass === 'function') {
    premblyWidget = new window.PremblyPass(config);
  } else {
    // Mock for the sake of avoiding crashes if the package doesn't actually export it
    class MockPremblyPass {
      constructor(cfg) { this.cfg = cfg; }
      on(event, cb) { this[event] = cb; }
      launch() { console.log('Mock widget launched with config', this.cfg); }
    }
    premblyWidget = new MockPremblyPass(config);
  }

  // Listen for success and error events
  if (typeof premblyWidget.on === 'function') {
    premblyWidget.on('success', (result) => {
      console.log('Verification Success:', result);
      resultDiv.innerHTML = `<p style="color: green;">Success: ${JSON.stringify(result)}</p>`;
    });

    premblyWidget.on('error', (error) => {
      console.error('Verification Error:', error);
      resultDiv.innerHTML = `<p style="color: red;">Error: ${JSON.stringify(error)}</p>`;
    });
  }

} catch (e) {
  console.error('Error initializing PremblyPass:', e);
}

verifyBtn.addEventListener('click', () => {
  if (premblyWidget) {
    if (typeof premblyWidget.launch === 'function') {
      premblyWidget.launch();
    } else if (typeof premblyWidget.open === 'function') {
      premblyWidget.open();
    } else if (typeof premblyWidget.start === 'function') {
      premblyWidget.start();
    } else {
      console.warn('Widget instance found but no launch method detected.');
    }
  } else {
    console.error('Prembly widget is not initialized.');
  }
});

